package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint_withValidFile() throws IOException {
        File tempFile = File.createTempFile("csv", ".tmp");
        tempFile.deleteOnExit();

        // Use Path instead of File to avoid ambiguity
        CSVPrinter printer = csvFormat.print(tempFile.toPath(), StandardCharsets.UTF_8);
        assertNotNull(printer);
        printer.close();
    }

    @Test
    public void testPrint_withNullFile_shouldThrowException() {
        assertThrows(NullPointerException.class, () -> csvFormat.print((File) null, StandardCharsets.UTF_8));
    }

    @Test
    public void testPrint_withNullCharset_shouldThrowException() throws IOException {
        File tempFile = File.createTempFile("csv", ".tmp");
        tempFile.deleteOnExit();

        assertThrows(NullPointerException.class, () -> csvFormat.print(tempFile.toPath(), null));
    }

    @Test
    public void testPrint_verifyPrinterOutputStreamWriterCharset() throws IOException {
        File tempFile = File.createTempFile("csv", ".tmp");
        tempFile.deleteOnExit();

        CSVPrinter printer = csvFormat.print(tempFile.toPath(), StandardCharsets.UTF_8);
        assertNotNull(printer);
        printer.close();
    }
}
